// Commits - accessor macros for runtime-loaded SHAs
#define FIXTURE_INITIAL_COMMIT fixture_sha_commit1()   // Root commit
#define FIXTURE_SECOND_COMMIT fixture_sha_commit2()    // Add second file
#define FIXTURE_MODIFY_COMMIT fixture_sha_commit3()    // Modify first file
#define FIXTURE_SUBDIR_COMMIT fixture_sha_commit4()    // Add file in subdir
#define FIXTURE_EXEC_COMMIT fixture_sha_commit5()      // Add executable
#define FIXTURE_FEATURE_COMMIT fixture_sha_feature_commit() // Add feature file (HEAD)

// Trees - accessor macros for runtime-loaded SHAs
#define FIXTURE_INITIAL_TREE fixture_sha_tree_initial()   // Initial tree (1 file)
#define FIXTURE_MODIFY_TREE fixture_sha_tree_modify()     // Modified tree
#define FIXTURE_HEAD_TREE fixture_sha_tree_head()         // HEAD tree (5 entries)
#define FIXTURE_SUBDIR_TREE fixture_sha_tree_subdir()     // Subdir tree

// Blobs - accessor macros for runtime-loaded SHAs
#define FIXTURE_FILE1_INITIAL_BLOB fixture_sha_blob_file1_initial()
#define FIXTURE_SCRIPT_BLOB fixture_sha_blob_script()

