TEST(tree_parse_entry_blob) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitTreeEntry entries[10];
    size_t count = git_read_tree(&repo, FIXTURE_INITIAL_TREE, entries, 10);

    TEST_ASSERT_TRUE(count >= 1);
    // Mode 100644 is regular file
    TEST_ASSERT_EQ(entries[0].mode, 0100644);
    TEST_ASSERT_STREQ(entries[0].sha, FIXTURE_FILE1_INITIAL_BLOB);

    git_repo_close(&repo);
}

TEST(tree_parse_entry_exec) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitTreeEntry entries[10];
    size_t count = git_read_tree(&repo, FIXTURE_HEAD_TREE, entries, 10);

    // Find the executable entry (script.sh)
    bool found_exec = false;
    for (size_t i = 0; i < count; i++) {
        if (strcmp(entries[i].name, "script.sh") == 0) {
            // Mode 100755 is executable
            TEST_ASSERT_EQ(entries[i].mode, 0100755);
            TEST_ASSERT_STREQ(entries[i].sha, FIXTURE_SCRIPT_BLOB);
            found_exec = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found_exec);

    git_repo_close(&repo);
}

TEST(tree_parse_entry_tree) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitTreeEntry entries[10];
    size_t count = git_read_tree(&repo, FIXTURE_HEAD_TREE, entries, 10);

    // Find the subdirectory entry
    bool found_subdir = false;
    for (size_t i = 0; i < count; i++) {
        if (strcmp(entries[i].name, "subdir") == 0) {
            // Mode 40000 is directory (tree)
            TEST_ASSERT_EQ(entries[i].mode, 040000);
            TEST_ASSERT_STREQ(entries[i].sha, FIXTURE_SUBDIR_TREE);
            found_subdir = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found_subdir);

    git_repo_close(&repo);
}

