TEST(tree_entry_name_extraction) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitTreeEntry entries[10];
    size_t count = git_read_tree(&repo, FIXTURE_HEAD_TREE, entries, 10);

    // Verify all expected names are present
    bool found_feature = false, found_file1 = false, found_file2 = false;
    bool found_script = false, found_subdir = false;

    for (size_t i = 0; i < count; i++) {
        if (strcmp(entries[i].name, "feature.txt") == 0) found_feature = true;
        if (strcmp(entries[i].name, "file1.txt") == 0) found_file1 = true;
        if (strcmp(entries[i].name, "file2.txt") == 0) found_file2 = true;
        if (strcmp(entries[i].name, "script.sh") == 0) found_script = true;
        if (strcmp(entries[i].name, "subdir") == 0) found_subdir = true;
    }

    TEST_ASSERT_TRUE(found_feature);
    TEST_ASSERT_TRUE(found_file1);
    TEST_ASSERT_TRUE(found_file2);
    TEST_ASSERT_TRUE(found_script);
    TEST_ASSERT_TRUE(found_subdir);

    git_repo_close(&repo);
}

TEST(tree_entry_sha_extraction) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitTreeEntry entries[10];
    size_t count = git_read_tree(&repo, FIXTURE_HEAD_TREE, entries, 10);

    // All SHAs should be 40 hex characters
    for (size_t i = 0; i < count; i++) {
        TEST_ASSERT_EQ(strlen(entries[i].sha), 40);
        // Verify all characters are valid hex
        for (int j = 0; j < 40; j++) {
            char c = entries[i].sha[j];
            bool is_hex = (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f');
            TEST_ASSERT_TRUE(is_hex);
        }
    }

    git_repo_close(&repo);
}

TEST(tree_read_flat_recursive) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // GitIndexEntry is ~4KB each due to MAX_PATH_LEN, use heap allocation
    GitIndexEntry* entries = new GitIndexEntry[100];
    size_t count = git_read_tree_flat(&repo, FIXTURE_HEAD_TREE, entries, 100, "");

    // Should flatten tree including subdir/file3.txt
    // Expected: feature.txt, file1.txt, file2.txt, script.sh, subdir/file3.txt
    TEST_ASSERT_EQ(count, 5);

    // Find the nested file
    bool found_nested = false;
    for (size_t i = 0; i < count; i++) {
        if (strcmp(entries[i].path, "subdir/file3.txt") == 0) {
            found_nested = true;
            break;
        }
    }
    TEST_ASSERT_TRUE(found_nested);

    delete[] entries;
    git_repo_close(&repo);
}

