TEST(history_get_sha_hex) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitHistory history = {};
    bool result = git_history_build(&repo, &history);
    TEST_ASSERT_TRUE(result);

    // Find initial commit and verify SHA roundtrip
    int idx = git_history_find_sha_hex(&history, FIXTURE_INITIAL_COMMIT);
    TEST_ASSERT_TRUE(idx >= 0);

    char sha_hex[41];
    git_history_get_sha_hex(&history, idx, sha_hex);
    TEST_ASSERT_STREQ(sha_hex, FIXTURE_INITIAL_COMMIT);

    git_history_free(&history);
    git_repo_close(&repo);
}

TEST(history_memory_cleanup) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    GitHistory history = {};
    bool result = git_history_build(&repo, &history);
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_TRUE(history.commits != nullptr);
    TEST_ASSERT_TRUE(history.graph != nullptr);

    git_history_free(&history);

    // After free, pointers should be null
    TEST_ASSERT_TRUE(history.commits == nullptr);
    TEST_ASSERT_TRUE(history.graph == nullptr);
    TEST_ASSERT_EQ(history.commit_count, 0);

    git_repo_close(&repo);
}

